964	    if ((false == logic_module_sram_port_ids.empty()) &&
965	        (ModulePortId::INVALID() != mem_module_sram_port_id)) {
966	      add_module_nets_between_logic_and_memory_sram_ports(
967	        module_manager, parent_module, logic_module, logic_instance_id,
