974	/********************************************************************
975	 * Add the port-to-port connection between a shared memory module and a set of
976	 * logic modules that are controlled by the same configuration bits. This is
977	 * used by bus-based multiplexers, where every bit of the output bus is
978	 * implemented as a separate multiplexer instance but all the instances share
979	 * a single selector (i.e. a single memory module).
980	 *
981	 * Unlike add_module_nets_between_logic_and_memory_sram_ports(), here the memory
982	 * output is the single driver (net source) that fans out to the SRAM port of
983	 * every logic instance (net sinks). This keeps the single-source-per-net
984	 * requirement of the netlist writer satisfied while sharing one memory.
985	 *******************************************************************/
986	static void add_module_nets_between_shared_memory_and_logic_sram_ports(
987	  ModuleManager& module_manager, const ModuleId& parent_module,
988	  const ModuleId& logic_module, const std::vector<size_t>& logic_instance_ids,
989	  const ModuleId& memory_module, const size_t& memory_instance_id,
990	  const std::vector<ModulePortId>& logic_module_sram_port_ids,
991	  const ModulePortId& mem_module_sram_port_id) {
992	  /* Find SRAM ports in logic module */
993	  std::vector<BasicPort> logic_module_sram_ports;
994	  for (const ModulePortId& logic_module_sram_port_id :
995	       logic_module_sram_port_ids) {
996	    logic_module_sram_ports.push_back(
997	      module_manager.module_port(logic_module, logic_module_sram_port_id));
998	  }
999	
1000	  /* Align the (possibly multiple) SRAM ports of the logic module against the
1001	   * single SRAM port of the memory module, exactly as the 1-to-1 variant does
1002	   */
1003	  BasicPort mem_module_port =
1004	    module_manager.module_port(memory_module, mem_module_sram_port_id);
1005	  std::vector<BasicPort> virtual_mem_module_ports;
1006	  size_t port_lsb = 0;
1007	  for (const BasicPort& logic_module_sram_port : logic_module_sram_ports) {
1008	    BasicPort virtual_port;
1009	    virtual_port.set_name(mem_module_port.get_name());
1010	    virtual_port.set_width(port_lsb,
1011	                           port_lsb + logic_module_sram_port.get_width() - 1);
1012	    virtual_mem_module_ports.push_back(virtual_port);
1013	    port_lsb = virtual_port.get_msb() + 1;
1014	  }
1015	  VTR_ASSERT(port_lsb == mem_module_port.get_msb() + 1);
1016	
1017	  /* Wire each memory output pin to the matching SRAM pin of every logic
1018	   * instance. One net per memory pin: source = memory, sinks = all logic
1019	   * instances */
1020	  for (size_t port_index = 0; port_index < logic_module_sram_ports.size();
1021	       ++port_index) {
1022	    for (size_t pin_id = 0;
1023	         pin_id < logic_module_sram_ports[port_index].pins().size(); ++pin_id) {
1024	      ModuleNetId net = module_manager.create_module_net(parent_module);
1025	      std::string net_name =
1026	        module_manager.module_name(memory_module) + std::string("_") +
1027	        std::to_string(memory_instance_id) + std::string("_") +
1028	        virtual_mem_module_ports[port_index].get_name() + std::string("_") +
1029	        std::to_string(virtual_mem_module_ports[port_index].pins()[pin_id]);
1030	      module_manager.set_net_name(parent_module, net, net_name);
1031	      /* Add net source: the shared memory output pin */
1032	      module_manager.add_module_net_source(
1033	        parent_module, net, memory_module, memory_instance_id,
1034	        mem_module_sram_port_id,
1035	        virtual_mem_module_ports[port_index].pins()[pin_id]);
1036	      /* Add net sinks: the corresponding SRAM pin of every logic instance */
1037	      for (const size_t& logic_instance_id : logic_instance_ids) {
1038	        module_manager.add_module_net_sink(
1039	          parent_module, net, logic_module, logic_instance_id,
1040	          logic_module_sram_port_ids[port_index],
1041	          logic_module_sram_ports[port_index].pins()[pin_id]);
1042	      }
1043	    }
1044	  }
1045	}
